{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"\\d clinical_info\" | head -50",
  "description": "View clinical_info schema"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"SELECT column_name FROM information_schema.columns WHERE table_name = 'clinical_info' AND (column_name ILIKE '%histology%' OR column_name ILIKE '%histological%' OR column_name ILIKE '%bcr%' OR column_name ILIKE '%barcode%' OR column_name ILIKE '%acronym%' OR column_name ILIKE '%type%');\"",
  "description": "Look for histology and barcode columns"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"SELECT column_name FROM information_schema.columns WHERE table_name = 'clinical_info' AND (column_name ILIKE '%acronym%' OR column_name ILIKE '%barcode%' OR column_name ILIKE '%patient%' OR column_name ILIKE '%cancer%');\"",
  "description": "Look for patient and cancer columns"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"SELECT column_name FROM information_schema.columns WHERE table_name = 'clinical_info' ORDER BY column_name;\" | head -100",
  "description": "List all clinical_info columns"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"SELECT \\\"Patient_description\\\", patient_id, histological_type FROM clinical_info LIMIT 5;\"",
  "description": "Sample clinical_info rows"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"SELECT DISTINCT histological_type FROM clinical_info WHERE \\\"Patient_description\\\" ILIKE '%glioma%' OR \\\"Patient_description\\\" ILIKE '%LGG%' LIMIT 30;\"",
  "description": "Check glioma patients"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"SELECT \\\"Patient_description\\\" FROM clinical_info WHERE histological_type = 'Astrocytoma' LIMIT 3;\"",
  "description": "See patient descriptions for Astrocytoma"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"SELECT DISTINCT histological_type, count(*) FROM clinical_info WHERE \\\"Patient_description\\\" ILIKE '%lower grade glioma%' GROUP BY histological_type;\"",
  "description": "Check LGG histological types"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"SELECT DISTINCT histological_type FROM clinical_info WHERE \\\"Patient_description\\\" ILIKE '%lower grade glioma%';\"",
  "description": "All LGG histology types"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"SELECT histological_type, count(*) FROM clinical_info WHERE histological_type LIKE '[%]' GROUP BY histological_type;\"",
  "description": "Check bracketed histology"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"SELECT substring(\\\"Patient_description\\\" FROM 'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}') AS barcode, histological_type FROM clinical_info WHERE \\\"Patient_description\\\" ILIKE '%lower grade glioma%' LIMIT 5;\"",
  "description": "Extract TCGA barcode from LGG patients"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_PANCANCER_ATLAS/query_dataset/pancancer_molecular.db' \"SELECT * FROM RNASeq_Expression WHERE Symbol='IGF2' LIMIT 5;\"",
  "description": "Sample IGF2 expression"
}

{
  "command": "psql -h 127.0.0.1 -U user -d pancancer_clinical -c \"COPY (SELECT substring(\\\"Patient_description\\\" FROM 'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}') AS barcode, histological_type FROM clinical_info WHERE \\\"Patient_description\\\" ILIKE '%lower grade glioma%' AND histological_type NOT LIKE '[%]') TO STDOUT WITH CSV HEADER\" > /tmp/lgg_patients.csv\nwc -l /tmp/lgg_patients.csv",
  "description": "Export LGG patient list"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_PANCANCER_ATLAS/query_dataset/pancancer_molecular.db' <<'EOF'
CREATE TEMP TABLE lgg AS SELECT * FROM read_csv_auto('/tmp/lgg_patients.csv');
SELECT l.histological_type,
       AVG(LOG10(r.normalized_count)) AS avg_log10_igf2,
       COUNT(*) AS n
FROM lgg l
JOIN RNASeq_Expression r ON l.barcode = r.ParticipantBarcode
WHERE r.Symbol = 'IGF2' AND r.normalized_count IS NOT NULL AND r.normalized_count > 0
GROUP BY l.histological_type;
EOF",
  "description": "Compute average log10 IGF2 expression by histology"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_PANCANCER_ATLAS/query_dataset/pancancer_molecular.db' <<'EOF'
CREATE TEMP TABLE lgg AS SELECT * FROM read_csv_auto('/tmp/lgg_patients.csv');
SELECT COUNT(DISTINCT l.barcode) AS lgg_count,
       COUNT(DISTINCT CASE WHEN r.ParticipantBarcode IS NOT NULL THEN l.barcode END) AS matched
FROM lgg l
LEFT JOIN RNASeq_Expression r ON l.barcode = r.ParticipantBarcode AND r.Symbol = 'IGF2';
EOF",
  "description": "Check how many LGG patients have IGF2 expression"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_PANCANCER_ATLAS/query_dataset/pancancer_molecular.db' <<'EOF'
SELECT COUNT(DISTINCT ParticipantBarcode) AS n_patients_with_igf2
FROM RNASeq_Expression WHERE Symbol='IGF2';
SELECT ParticipantBarcode FROM RNASeq_Expression WHERE Symbol='IGF2' AND ParticipantBarcode ILIKE 'TCGA-S9%' LIMIT 5;
EOF",
  "description": "Check IGF2 coverage and sample barcodes"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_PANCANCER_ATLAS/query_dataset/pancancer_molecular.db' <<'EOF'\nSELECT r.ParticipantBarcode, r.Symbol FROM RNASeq_Expression r WHERE r.ParticipantBarcode='TCGA-S9-A7J1' LIMIT 10;\nEOF",
  "description": "Check gene coverage for a specific patient"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_PANCANCER_ATLAS/query_dataset/pancancer_molecular.db' <<'EOF'\nSELECT COUNT(*) total, COUNT(normalized_count) non_null, SUM(CASE WHEN normalized_count <= 0 THEN 1 ELSE 0 END) zero_or_neg\nFROM RNASeq_Expression WHERE Symbol='IGF2';\nEOF",
  "description": "Check IGF2 expression value validity"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_PANCANCER_ATLAS/query_dataset/pancancer_molecular.db' <<'EOF'
CREATE TEMP TABLE lgg AS SELECT * FROM read_csv_auto('/tmp/lgg_patients.csv');
SELECT l.histological_type,
       printf('%.6f', AVG(LOG10(r.normalized_count))) AS avg_log10_igf2,
       COUNT(*) AS n
FROM lgg l
JOIN RNASeq_Expression r ON l.barcode = r.ParticipantBarcode
WHERE r.Symbol = 'IGF2'
GROUP BY l.histological_type;
EOF",
  "description": "Final averages with precision"
}
